    "load_code": "// ===== K12纵版射击游戏 Phaser.js 资产加载代码 =====
// 在 preload() 中调用
const BASE = 'assets/plane-shooter/';

// 玩家飞机（三级火力）
this.load.image('player_lv1', BASE + 'PNG/Plane/01/Plane1Up_254x271.png');
this.load.image('player_lv2', BASE + 'PNG/Plane/01/Plane2Up_254x271.png');
this.load.image('player_lv3', BASE + 'PNG/Plane/01/Plane3Up_254x271.png');

// 普通敌机（4波）
this.load.image('enemy_wave1', BASE + 'PNG/Enemy/Enemy02_267x271.png');
this.load.image('enemy_wave2', BASE + 'PNG/Enemy/Enemy04_267x271.png');
this.load.image('enemy_wave3', BASE + 'PNG/Enemy/Enemy05_267x271.png');
this.load.image('enemy_wave4', BASE + 'PNG/Enemy/Enemy08_267x271.png');

// 小Boss（第5波）
this.load.image('enemy_boss', BASE + 'PNG/Enemy/Enemy03_267x271.png');

// 子弹
this.load.image('bullet_player', BASE + 'PNG/Bullets/01Bullets_86x86.png');
this.load.image('bullet_enemy',  BASE + 'PNG/Bullets/02Bullets_86x86.png');

// 背景
this.load.image('bg_main',  BASE + 'PNG/Backgrounds/01Background_298x1421.png');
this.load.image('bg_cloud', BASE + 'PNG/Backgrounds/WhiteCloud_298x1421.png');

// 爆炸特效（4帧）
this.load.image('explosion_1', BASE + 'PNG/Items_and_Other/ExplosionSprite/01_149x149.png');
this.load.image('explosion_2', BASE + 'PNG/Items_and_Other/ExplosionSprite/02_149x149.png');
this.load.image('explosion_3', BASE + 'PNG/Items_and_Other/ExplosionSprite/03_149x149.png');
this.load.image('explosion_4', BASE + 'PNG/Items_and_Other/ExplosionSprite/04_149x149.png');

// 道具P（火力强化）
this.load.image('item_powerup', BASE + 'PNG/Items_and_Other/BoxItems/CoinBoxSprite01_149x149.png');

// 游戏UI
this.load.image('ui_bomb_btn',    BASE + 'PNG/User_Interface/PanelUi/BombBtn_99x101.png');
this.load.image('ui_health_bar',  BASE + 'PNG/User_Interface/PanelUi/HealthBar_274x41.png');
this.load.image('ui_red_health',  BASE + 'PNG/User_Interface/PanelUi/RedHealthBar_175x38.png');

// 胜利界面
this.load.image('ui_win_bg',      BASE + 'PNG/User_Interface/WinConditionsBox/Background_284x239.png');
this.load.image('ui_win_continue',BASE + 'PNG/User_Interface/WinConditionsBox/ContinueBtn_140x49.png');
this.load.image('ui_win_menu',    BASE + 'PNG/User_Interface/WinConditionsBox/MenuBtn_140x49.png');
this.load.image('ui_win_score',   BASE + 'PNG/User_Interface/WinConditionsBox/totalscoreText_188x22.png');

// 失败界面
this.load.image('ui_fail_bg',     BASE + 'PNG/User_Interface/failConditionsBox/imageBg_312x164.png');
this.load.image('ui_fail_restart',BASE + 'PNG/User_Interface/failConditionsBox/RestartBtn_138x48.png');
this.load.image('ui_fail_menu',   BASE + 'PNG/User_Interface/failConditionsBox/MenuBtn_140x49.png');",
    "usage_snippets": {
      "scrolling_background": "// 纵向卷轴背景循环滚动（在 create() 中）
const bg1 = this.add.image(0, 0, 'bg_main').setOrigin(0, 0);
const bg2 = this.add.image(0, -1421, 'bg_main').setOrigin(0, 0);
// 在 update() 中
bg1.y += scrollSpeed;
bg2.y += scrollSpeed;
if (bg1.y >= 1421) bg1.y = bg2.y - 1421;
if (bg2.y >= 1421) bg2.y = bg1.y - 1421;",
      "player_plane": "// 创建玩家飞机（在 create() 中）
const player = this.physics.add.sprite(gameWidth/2, gameHeight - 100, 'player_lv1');
player.setCollideWorldBounds(true);
player.setScale(0.4); // 缩放至合适大小（原始254x271）

// 切换火力等级（拾取道具P后）
player.setTexture('player_lv2'); // 一次强化
player.setTexture('player_lv3'); // 二次强化",
      "enemy_spawn": "// 按波次生成敌机（在 create() 中）
const enemyKeys = ['enemy_wave1','enemy_wave2','enemy_wave3','enemy_wave4'];
const waveKey = enemyKeys[currentWave - 1]; // currentWave: 1-4
const enemy = this.physics.add.sprite(x, -50, waveKey);
enemy.setScale(0.35);
enemy.setVelocityY(enemySpeed);

// 第5波Boss
const boss = this.physics.add.sprite(gameWidth/2, -100, 'enemy_boss');
boss.setScale(0.6);
boss.health = 20; // Boss血量",
      "bullet_fire": "// 发射子弹（空格键持续射击）
// 玩家子弹（向上）
const pBullet = this.physics.add.sprite(player.x, player.y - 30, 'bullet_player');
pBullet.setScale(0.4);
pBullet.setVelocityY(-600);

// 敌机子弹（向下）
const eBullet = this.physics.add.sprite(enemy.x, enemy.y + 30, 'bullet_enemy');
eBullet.setScale(0.4);
eBullet.setVelocityY(300);",
      "explosion_anim": "// 爆炸动画（敌机被击毁时）
// 在 create() 中注册动画
this.anims.create({
  key: 'explode',
  frames: [
    { key: 'explosion_1' },
    { key: 'explosion_2' },
    { key: 'explosion_3' },
    { key: 'explosion_4' }
  ],
  frameRate: 12,
  repeat: 0
});
// 播放爆炸
const boom = this.add.sprite(enemy.x, enemy.y, 'explosion_1');
boom.play('explode');
boom.on('animationcomplete', () => boom.destroy());",
      "power_up_drop": "// 道具P掉落（敌机被击毁时随机掉落）
if (Phaser.Math.Between(1, 100) <= 30) { // 30%概率
  const item = this.physics.add.sprite(enemy.x, enemy.y, 'item_powerup');
  item.setScale(0.5);
  item.setVelocityY(150);
  // 拾取检测
  this.physics.add.overlap(player, item, () => {
    item.destroy();
    powerLevel = Math.min(powerLevel + 1, 3); // 最高3级
    player.setTexture('player_lv' + powerLevel);
  });
}",
      "bomb_effect": "// 炸弹特效（X键，全屏清除敌机子弹）
function triggerBomb() {
  if (bombCooldown > 0) return; // 冷却中
  // 清除所有敌机子弹
  enemyBullets.clear(true, true);
  // 全屏闪光效果
  const flash = this.add.rectangle(0, 0, gameWidth, gameHeight, 0xffffff, 0.8).setOrigin(0);
  this.tweens.add({ targets: flash, alpha: 0, duration: 300, onComplete: () => flash.destroy() });
  bombCooldown = 15000; // 15秒冷却
}",
      "hud_display": "// HUD信息显示（在 create() 中）
// 生命值血条
const healthBar = this.add.image(10, 10, 'ui_health_bar').setOrigin(0, 0).setScale(0.8);
// 炸弹按钮图标
const bombIcon = this.add.image(gameWidth - 60, gameHeight - 60, 'ui_bomb_btn').setScale(0.5);
// 分数文字（用 Phaser 文字对象）
const scoreText = this.add.text(10, 60, '分数: 0', { fontSize: '20px', fill: '#ffffff' });
// 波次提示
const waveText = this.add.text(gameWidth/2, 30, '第1波', { fontSize: '24px', fill: '#ffff00' }).setOrigin(0.5);
// 炸弹冷却提示
const bombCdText = this.add.text(gameWidth - 60, gameHeight - 20, '就绪', { fontSize: '14px', fill: '#00ff00' }).setOrigin(0.5);",
      "win_screen": "// 胜利界面（在 create() 中）
const winBg = this.add.image(gameWidth/2, gameHeight/2, 'ui_win_bg').setScale(1.2);
const winScore = this.add.image(gameWidth/2, gameHeight/2 - 40, 'ui_win_score');
const scoreVal = this.add.text(gameWidth/2, gameHeight/2, '最终得分: ' + finalScore, { fontSize: '28px', fill: '#ffcc00' }).setOrigin(0.5);
const continueBtn = this.add.image(gameWidth/2 - 80, gameHeight/2 + 60, 'ui_win_continue').setInteractive();
const menuBtn = this.add.image(gameWidth/2 + 80, gameHeight/2 + 60, 'ui_win_menu').setInteractive();
continueBtn.on('pointerdown', () => this.scene.restart());
menuBtn.on('pointerdown', () => this.scene.start('MenuScene'));",
      "fail_screen": "// 失败界面（在 create() 中）
const failBg = this.add.image(gameWidth/2, gameHeight/2, 'ui_fail_bg').setScale(1.5);
const failTitle = this.add.text(gameWidth/2, gameHeight/2 - 60, '失败', { fontSize: '48px', fill: '#ff4444' }).setOrigin(0.5);
const scoreVal = this.add.text(gameWidth/2, gameHeight/2, '最终得分: ' + finalScore, { fontSize: '24px', fill: '#ffffff' }).setOrigin(0.5);
const restartBtn = this.add.image(gameWidth/2 - 80, gameHeight/2 + 60, 'ui_fail_restart').setInteractive();
const menuBtn = this.add.image(gameWidth/2 + 80, gameHeight/2 + 60, 'ui_fail_menu').setInteractive();
restartBtn.on('pointerdown', () => this.scene.restart());
menuBtn.on('pointerdown', () => this.scene.start('MenuScene'));"
    },
