import { create } from 'zustand';

interface GameState {
  score: number;
  lives: number;
  wave: number;
  bombCooldown: number; // 0 means ready, otherwise ms remaining
  gameStatus: 'menu' | 'playing' | 'win' | 'fail';
  addScore: (points: number) => void;
  setLives: (lives: number) => void;
  setWave: (wave: number) => void;
  setBombCooldown: (cd: number) => void;
  setGameStatus: (status: 'menu' | 'playing' | 'win' | 'fail') => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  score: 0,
  lives: 3,
  wave: 1,
  bombCooldown: 0,
  gameStatus: 'playing',
  addScore: (points) => set((state) => ({ score: state.score + points })),
  setLives: (lives) => set({ lives }),
  setWave: (wave) => set({ wave }),
  setBombCooldown: (cd) => set({ bombCooldown: cd }),
  setGameStatus: (status) => set({ gameStatus: status }),
  resetGame: () => set({ score: 0, lives: 3, wave: 1, bombCooldown: 0, gameStatus: 'playing' }),
}));

