import { Scene } from 'phaser';
import { ASSETS } from '../assets';
import { EventBus } from '../EventBus';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // Load all assets
    for (const [key, path] of Object.entries(ASSETS)) {
      this.load.image(key, path);
    }

    // Auto-generate fallback texture on load error
    this.load.on('loaderror', (file: any) => {
      console.error('Failed to load asset', file.key, file.src);
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });
  }

  create() {
    // Setup animations
    this.anims.create({
      key: 'explode',
      frames: [
        { key: 'explosion_1' },
        { key: 'explosion_2' },
        { key: 'explosion_3' },
        { key: 'explosion_4' },
      ],
      frameRate: 12,
      repeat: 0,
    });

    this.scene.start('Game');
  }
}

import { Scene } from 'phaser';
import { CONSTANTS, WAVES } from '../constants';
import { useGameStore } from '../store';
import { EventBus } from '../EventBus';

export class Game extends Scene {
  private bg1!: Phaser.GameObjects.Image;
  private bg2!: Phaser.GameObjects.Image;
  private bgCloud1!: Phaser.GameObjects.Image;
  private bgCloud2!: Phaser.GameObjects.Image;

  private player!: Phaser.Physics.Arcade.Sprite;
  private playerBullets!: Phaser.Physics.Arcade.Group;
  private enemies!: Phaser.Physics.Arcade.Group;
  private enemyBullets!: Phaser.Physics.Arcade.Group;
  private powerups!: Phaser.Physics.Arcade.Group;

  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private spaceKey!: Phaser.Input.Keyboard.Key;
  private xKey!: Phaser.Input.Keyboard.Key;

  private lastFired = 0;
  private fireRate = 200;
  private powerLevel = 1;
  private currentWaveIndex = 0;
  private enemiesSpawned = 0;
  private waveInProgress = false;
  private isGameOver = false;

  private targetX: number = CONSTANTS.GAME_WIDTH / 2;
  private targetY: number = CONSTANTS.GAME_HEIGHT - 100;

  constructor() {
    super('Game');
  }

  create() {
    this.isGameOver = false;
    this.powerLevel = 1;
    this.currentWaveIndex = 0;
    this.enemiesSpawned = 0;
    this.waveInProgress = false;

    // Reset store
    useGameStore.getState().resetGame();

    // Background
    this.bg1 = this.add.image(0, 0, 'bg_main').setOrigin(0, 0).setDisplaySize(CONSTANTS.GAME_WIDTH, CONSTANTS.GAME_HEIGHT);
    this.bg2 = this.add.image(0, -CONSTANTS.GAME_HEIGHT, 'bg_main').setOrigin(0, 0).setDisplaySize(CONSTANTS.GAME_WIDTH, CONSTANTS.GAME_HEIGHT);

    this.bgCloud1 = this.add.image(0, 0, 'bg_cloud').setOrigin(0, 0).setDisplaySize(CONSTANTS.GAME_WIDTH, CONSTANTS.GAME_HEIGHT);
    this.bgCloud2 = this.add.image(0, -CONSTANTS.GAME_HEIGHT, 'bg_cloud').setOrigin(0, 0).setDisplaySize(CONSTANTS.GAME_WIDTH, CONSTANTS.GAME_HEIGHT);

    // Player
    this.player = this.physics.add.sprite(CONSTANTS.GAME_WIDTH / 2, CONSTANTS.GAME_HEIGHT - 100, 'player_lv1');
    this.player.setScale(0.4);
    this.player.setCollideWorldBounds(true);

    const body = this.player.body as Phaser.Physics.Arcade.Body;
    body.setSize(100, 100);
    body.setOffset(77, 85);

    this.targetX = this.player.x;
    this.targetY = this.player.y;

    // Groups
    this.playerBullets = this.physics.add.group({ classType: Phaser.Physics.Arcade.Sprite, maxSize: 30, runChildUpdate: true });
    this.enemies = this.physics.add.group({ classType: Phaser.Physics.Arcade.Sprite, runChildUpdate: true });
    this.enemyBullets = this.physics.add.group({ classType: Phaser.Physics.Arcade.Sprite, maxSize: 100, runChildUpdate: true });
    this.powerups = this.physics.add.group();

    // Collisions
    this.physics.add.overlap(this.playerBullets, this.enemies, this.hitEnemy, undefined, this);
    this.physics.add.overlap(this.player, this.enemies, this.crashEnemy, undefined, this);
    this.physics.add.overlap(this.player, this.enemyBullets, this.hitPlayer, undefined, this);
    this.physics.add.overlap(this.player, this.powerups, this.collectPowerup, undefined, this);
    // Player bullets and enemy bullets cancel each other
    this.physics.add.overlap(this.playerBullets, this.enemyBullets, (pb, eb) => {
      pb.destroy();
      eb.destroy();
    });

    // Input
    this.cursors = this.input.keyboard!.createCursorKeys();
    this.spaceKey = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);
    this.xKey = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.X);

    // Initial delay before starting wave 1
    this.time.delayedCall(2000, () => {
      this.startNextWave();
    });
  }

  update(time: number, delta: number) {
    if (this.isGameOver) return;

    // Background scroll
    const scrollSpeedMain = 1;
    const scrollSpeedCloud = 2;

    this.bg1.y += scrollSpeedMain;
    this.bg2.y += scrollSpeedMain;
    if (this.bg1.y >= CONSTANTS.GAME_HEIGHT) this.bg1.y = this.bg2.y - CONSTANTS.GAME_HEIGHT;
    if (this.bg2.y >= CONSTANTS.GAME_HEIGHT) this.bg2.y = this.bg1.y - CONSTANTS.GAME_HEIGHT;

    this.bgCloud1.y += scrollSpeedCloud;
    this.bgCloud2.y += scrollSpeedCloud;
    if (this.bgCloud1.y >= CONSTANTS.GAME_HEIGHT) this.bgCloud1.y = this.bgCloud2.y - CONSTANTS.GAME_HEIGHT;
    if (this.bgCloud2.y >= CONSTANTS.GAME_HEIGHT) this.bgCloud2.y = this.bgCloud1.y - CONSTANTS.GAME_HEIGHT;

    // Player movement
    let velocityX = 0;
    let velocityY = 0;

    if (this.cursors.left.isDown) velocityX = -CONSTANTS.PLAYER_SPEED;
    else if (this.cursors.right.isDown) velocityX = CONSTANTS.PLAYER_SPEED;

    if (this.cursors.up.isDown) velocityY = -CONSTANTS.PLAYER_SPEED;
    else if (this.cursors.down.isDown) velocityY = CONSTANTS.PLAYER_SPEED;

    this.player.setVelocity(velocityX, velocityY);

    // Shooting
    if (this.spaceKey.isDown && time > this.lastFired) {
      this.firePlayerBullet();
      this.lastFired = time + this.fireRate;
    }

    // Bomb
    if (Phaser.Input.Keyboard.JustDown(this.xKey)) {
      this.useBomb();
    }

    // Update Bomb Cooldown in store
    const storeCd = useGameStore.getState().bombCooldown;
    if (storeCd > 0) {
      useGameStore.getState().setBombCooldown(Math.max(0, storeCd - delta));
    }

    // Enemy cleanup (out of bounds)
    this.enemies.getChildren().forEach((enemy: any) => {
      if (enemy.y > CONSTANTS.GAME_HEIGHT + 100) {
        enemy.destroy();
      }
    });

    // Bullets cleanup
    this.playerBullets.getChildren().forEach((bullet: any) => {
      if (bullet.y < -50) bullet.destroy();
    });
    this.enemyBullets.getChildren().forEach((bullet: any) => {
      if (bullet.y > CONSTANTS.GAME_HEIGHT + 50 || bullet.y < -50 || bullet.x < -50 || bullet.x > CONSTANTS.GAME_WIDTH + 50) {
        bullet.destroy();
      }
    });
    this.powerups.getChildren().forEach((p: any) => {
      if (p.y > CONSTANTS.GAME_HEIGHT + 50) p.destroy();
    });

    // Check wave progress
    if (this.waveInProgress && this.enemiesSpawned >= WAVES[this.currentWaveIndex].count && this.enemies.countActive() === 0) {
      this.waveInProgress = false;
      this.time.delayedCall(2000, () => this.startNextWave());
    }
  }

  private startNextWave() {
    if (this.isGameOver) return;

    if (this.currentWaveIndex >= CONSTANTS.MAX_WAVES) {
      this.winGame();
      return;
    }

    const waveData = WAVES[this.currentWaveIndex];
    useGameStore.getState().setWave(waveData.wave);
    this.enemiesSpawned = 0;
    this.waveInProgress = true;

    this.spawnEnemyTimer(waveData);
  }

  private spawnEnemyTimer(waveData: typeof WAVES[0]) {
    if (this.isGameOver || this.enemiesSpawned >= waveData.count) return;

    const x = Phaser.Math.Between(50, CONSTANTS.GAME_WIDTH - 50);
    const enemy = this.enemies.create(x, -50, waveData.key) as Phaser.Physics.Arcade.Sprite;

    const scale = waveData.wave === 5 ? 0.6 : 0.35;
    enemy.setScale(scale);
    enemy.setData('hp', waveData.hp);
    enemy.setData('score', waveData.score);

    // adjust hitbox
    const body = enemy.body as Phaser.Physics.Arcade.Body;
    const w = enemy.width;
    const h = enemy.height;
    body.setSize(w * 0.6, h * 0.6);

    if (waveData.wave === 5) {
      // Boss behavior
      enemy.setVelocity(0, waveData.speed);
      this.time.addEvent({
        delay: 2000,
        callback: () => {
          if (enemy.active) enemy.setVelocityY(0);
        }
      });
      // Boss movement tween
      this.tweens.add({
        targets: enemy,
        x: { from: 100, to: CONSTANTS.GAME_WIDTH - 100 },
        duration: 3000,
        yoyo: true,
        repeat: -1,
        ease: 'Sine.easeInOut',
        delay: 2000
      });
    } else {
      // Normal behavior
      enemy.setVelocity(Phaser.Math.Between(-20, 20), waveData.speed);
    }

    this.enemiesSpawned++;

    // Enemy shooting
    this.time.addEvent({
      delay: waveData.bulletCD,
      loop: true,
      callback: () => {
        if (!enemy.active || this.isGameOver) return;
        this.fireEnemyBullet(enemy, waveData.wave === 5);
      }
    });

    // Next spawn
    if (this.enemiesSpawned < waveData.count) {
      this.time.delayedCall(Phaser.Math.Between(800, 1500), () => this.spawnEnemyTimer(waveData));
    } else {
      this.currentWaveIndex++;
    }
  }

  private firePlayerBullet() {
    const offsets = [];
    if (this.powerLevel === 1) offsets.push({ x: 0, y: -20 });
    else if (this.powerLevel === 2) offsets.push({ x: -15, y: -10 }, { x: 15, y: -10 });
    else if (this.powerLevel >= 3) offsets.push({ x: -25, y: 0 }, { x: 0, y: -20 }, { x: 25, y: 0 });

    offsets.forEach(off => {
      const bullet = this.playerBullets.create(this.player.x + off.x, this.player.y + off.y, 'bullet_player') as Phaser.Physics.Arcade.Sprite;
      if (bullet) {
        bullet.setScale(0.4);
        bullet.setVelocityY(-CONSTANTS.BULLET_SPEED);
      }
    });
  }

  private fireEnemyBullet(enemy: Phaser.Physics.Arcade.Sprite, isBoss: boolean) {
    if (isBoss) {
      // Boss bullet pattern: simple spread, but low density
      const angles = [-30, 0, 30];
      angles.forEach(angle => {
        const bullet = this.enemyBullets.create(enemy.x, enemy.y + 30, 'bullet_enemy') as Phaser.Physics.Arcade.Sprite;
        if (bullet) {
          bullet.setScale(0.4);
          this.physics.velocityFromAngle(angle + 90, CONSTANTS.ENEMY_BULLET_SPEED, bullet.body!.velocity);
        }
      });
    } else {
      // Aim at player
      const angle = Phaser.Math.Angle.Between(enemy.x, enemy.y, this.player.x, this.player.y);
      const bullet = this.enemyBullets.create(enemy.x, enemy.y + 30, 'bullet_enemy') as Phaser.Physics.Arcade.Sprite;
      if (bullet) {
        bullet.setScale(0.4);
        this.physics.velocityFromRotation(angle, CONSTANTS.ENEMY_BULLET_SPEED, bullet.body!.velocity);
      }
    }
  }

  private useBomb() {
    if (this.isGameOver) return;

    const cd = useGameStore.getState().bombCooldown;
    if (cd > 0) return;

    useGameStore.getState().setBombCooldown(CONSTANTS.BOMB_COOLDOWN);

    // Clear enemy bullets
    this.enemyBullets.clear(true, true);

    // Deal 5 damage to all enemies on screen
    this.enemies.getChildren().forEach((e: any) => {
      let hp = e.getData('hp');
      hp -= 5;
      if (hp <= 0) {
        this.destroyEnemy(e);
      } else {
        e.setData('hp', hp);
      }
    });

    // Flash effect
    const flash = this.add.rectangle(0, 0, CONSTANTS.GAME_WIDTH, CONSTANTS.GAME_HEIGHT, 0xffea00, 0.8).setOrigin(0);
    this.tweens.add({
      targets: flash,
      alpha: 0,
      duration: 500,
      onComplete: () => flash.destroy()
    });
  }

  private hitEnemy(bullet: any, enemy: any) {
    bullet.destroy();

    let hp = enemy.getData('hp');
    hp -= 1;
    enemy.setData('hp', hp);

    if (hp <= 0) {
      this.destroyEnemy(enemy);
    } else {
      // hit flash
      enemy.setTint(0xff0000);
      this.time.delayedCall(100, () => {
        if (enemy && enemy.active) enemy.clearTint();
      });
    }
  }

  private destroyEnemy(enemy: any) {
    const score = enemy.getData('score');
    useGameStore.getState().addScore(score);

    // Explosion
    const boom = this.add.sprite(enemy.x, enemy.y, 'explosion_1').setScale(0.8).play('explode');
    boom.on('animationcomplete', () => boom.destroy());

    // Drop powerup (10% chance)
    if (Phaser.Math.FloatBetween(0, 1) < 0.1) {
      const p = this.powerups.create(enemy.x, enemy.y, 'item_powerup') as Phaser.Physics.Arcade.Sprite;
      p.setScale(0.5);
      p.setVelocityY(100);
    }

    enemy.destroy();
  }

  private crashEnemy(player: any, enemy: any) {
    this.destroyEnemy(enemy);
    this.hitPlayer(player, null);
  }

  private hitPlayer(player: any, bullet: any) {
    if (bullet) bullet.destroy();

    if (!this.player.active || this.player.alpha < 1) return; // invulnerable

    const lives = useGameStore.getState().lives - 1;
    useGameStore.getState().setLives(lives);

    if (lives <= 0) {
      this.failGame();
    } else {
      this.powerLevel = 1;
      this.player.setTexture('player_lv1');

      // Explosion
      const boom = this.add.sprite(this.player.x, this.player.y, 'explosion_1').setScale(0.8).play('explode');
      boom.on('animationcomplete', () => boom.destroy());

      // Invulnerability blink
      this.tweens.add({
        targets: this.player,
        alpha: 0.2,
        yoyo: true,
        repeat: 5,
        duration: 200,
        onComplete: () => {
          if (this.player.active) this.player.alpha = 1;
        }
      });
    }
  }

  private collectPowerup(player: any, powerup: any) {
    powerup.destroy();
    useGameStore.getState().addScore(50);
    if (this.powerLevel < 3) {
      this.powerLevel++;
      this.player.setTexture(`player_lv${this.powerLevel}`);
    }
  }

  private winGame() {
    if (this.isGameOver) return;
    this.isGameOver = true;
    this.physics.pause();
    this.time.delayedCall(1000, () => {
      useGameStore.getState().setGameStatus('win');
      EventBus.emit('game-over');
    });
  }

  private failGame() {
    if (this.isGameOver) return;
    this.isGameOver = true;
    this.player.setActive(false).setVisible(false);

    const boom = this.add.sprite(this.player.x, this.player.y, 'explosion_1').setScale(1.2).play('explode');
    boom.on('animationcomplete', () => boom.destroy());

    this.physics.pause();
    this.time.delayedCall(1500, () => {
      useGameStore.getState().setGameStatus('fail');
      EventBus.emit('game-over');
    });
  }
}

