import React, { useEffect, useRef } from 'react';
import { Game } from 'phaser';
import { config } from './game/main';
import { useGameStore } from './game/store';
import { EventBus } from './game/EventBus';
import { CONSTANTS, WAVES } from './game/constants';
import { Bomb, Heart, RefreshCw, Trophy } from 'lucide-react';

function App() {
  const initialized = useRef(false);
  const gameRef = useRef<Game | null>(null);

  const { score, lives, wave, bombCooldown, gameStatus, resetGame, setGameStatus } = useGameStore();

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    gameRef.current = new Game(config);

    EventBus.on('game-over', () => {
      // Handled by zustand state
    });

    return () => {
      gameRef.current?.destroy(true);
      initialized.current = false;
      EventBus.removeAllListeners();
    };
  }, []);

  const handleRestart = () => {
    resetGame();
    if (gameRef.current) {
      gameRef.current.scene.stop('Game');
      gameRef.current.scene.start('Game');
    }
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#1A2035] font-sans flex justify-center items-center">
      {/* Game Container constraints to Mobile Ratio */}
      <div className="relative shadow-2xl overflow-hidden" style={{ width: CONSTANTS.GAME_WIDTH, height: CONSTANTS.GAME_HEIGHT, maxWidth: '100vw', maxHeight: '100vh', aspectRatio: '540/960' }}>
        <div id="game-container" className="w-full h-full" />

        {/* HUD */}
        {gameStatus === 'playing' && (
          <>
            {/* Top Bar */}
            <div className="absolute top-0 left-0 w-full p-4 flex justify-between items-start pointer-events-none text-white drop-shadow-md">
              <div className="flex flex-col">
                <span className="text-xl font-bold uppercase tracking-wider text-[#00E5FF]">得分</span>
                <span className="text-3xl font-mono">{score.toString().padStart(6, '0')}</span>
              </div>
              <div className="flex flex-col items-center">
                <span className="text-lg font-bold bg-[#FF3D00] px-3 py-1 rounded-full">第 {wave} 波</span>
                {wave === CONSTANTS.MAX_WAVES && <span className="text-xs mt-1 text-[#FFEA00] animate-pulse">Boss 出现!</span>}
              </div>
              <div className="flex flex-col items-end">
                <span className="text-xl font-bold uppercase tracking-wider text-[#FFEA00]">生命</span>
                <div className="flex gap-1 mt-1">
                  {[...Array(CONSTANTS.MAX_LIVES)].map((_, i) => (
                    <div key={i} className={`w-6 h-6 rounded-full border-2 ${i < lives ? 'bg-[#00E5FF] border-[#00E5FF]' : 'border-gray-500'}`} />
                  ))}
                </div>
              </div>
            </div>

            {/* Bottom Info */}
            <div className="absolute bottom-0 left-0 w-full p-4 pointer-events-none flex justify-between items-end">
              <div className="text-white/60 text-sm font-mono space-y-1">
                <div>[↑↓←→] 移动</div>
                <div>[SPACE] 射击</div>
                <div>[X] 炸弹</div>
              </div>

              <div className="flex flex-col items-end gap-2">
                <div className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-transform ${bombCooldown === 0 ? 'bg-[#FFEA00] text-black scale-110' : 'bg-gray-800 text-gray-400'}`}>
                  <Bomb size={24} />
                  <span className="font-bold font-mono">
                    {bombCooldown === 0 ? 'READY' : `${(bombCooldown / 1000).toFixed(1)}s`}
                  </span>
                </div>
              </div>
            </div>
          </>
        )}

        {/* Win / Fail Overlays */}
        {(gameStatus === 'win' || gameStatus === 'fail') && (
          <div className="absolute inset-0 bg-black/80 flex flex-col justify-center items-center backdrop-blur-sm p-6 z-50">
            <div className={`w-full max-w-sm rounded-3xl p-8 flex flex-col items-center shadow-2xl border-4 ${gameStatus === 'win' ? 'border-[#00E5FF] bg-[#1A2035]' : 'border-[#FF3D00] bg-[#1A2035]'}`}>
              {gameStatus === 'win' ? (
                <Trophy size={64} className="text-[#FFEA00] mb-4" />
              ) : (
                <Heart size={64} className="text-[#FF3D00] mb-4 stroke-[3]" />
              )}

              <h2 className={`text-4xl font-black mb-2 ${gameStatus === 'win' ? 'text-[#00E5FF]' : 'text-[#FF3D00]'}`}>
                {gameStatus === 'win' ? '任务完成！' : '任务失败'}
              </h2>

              <div className="flex flex-col items-center my-8 text-white">
                <span className="text-gray-400 mb-1 uppercase tracking-widest">最终得分</span>
                <span className="text-5xl font-mono text-[#FFEA00] font-bold">{score}</span>
              </div>

              <button 
                onClick={handleRestart}
                className="group relative flex items-center justify-center gap-3 w-full py-4 rounded-xl font-bold text-xl uppercase tracking-wider text-black bg-[#00E5FF] hover:bg-white transition-all transform hover:-translate-y-1 active:translate-y-0"
              >
                <RefreshCw size={24} className="group-hover:rotate-180 transition-transform duration-500" />
                重新开始
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;

